using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=5e5+5;
int a[MAXN],n,b[MAXN],c[MAXN],m,d[MAXN],f;
bool check(int x)
{
	FOR(i,1,m)
	{
		d[i]=0;
	}
	FOR(i,1,n)
	{
		d[a[i]]+=b[i];
	}
	FOR(i,1,m)
	{
        if(d[i]<x)return false;
		d[i]-=x;
	}
	int tmp=x;
	FOR(i,1,n)
	{
		if(d[a[i]]>0&&c[i])
		{
			--d[a[i]];
			--tmp;
		}
	} 
	return (tmp<=0);
} 
int find_ans()
{
	int l=0,r=f,ans=0;
	wh(l<=r)
	{
		int mid=(l+r)>>1; 
		if(check(mid))l=mid+1,ans=mid;
		else r=mid-1;
	}
	return ans;
}
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
	cin>>n>>m;
	FOR(i,1,n)
	{
		a[i]=read(),b[i]=read(),c[i]=read();
		f+=c[i];
	}
	cout<<find_ans();
    return false;
}
